form:Form.form:Scripts:
		function ChgActual()
{	
	if(Ctrl("l_actual"))
	{
		if(Ctrl("l_actual").GetXValue() == "1")
		{		
			CtrlEnabled("f_egreso", false);
			CtrlEnabled("oi_mot_egr", false);
			if(Ctrl("f_egreso"))
				Ctrl("f_egreso").SetXValue("");
			if(Ctrl("oi_mot_egr"))
				Ctrl("oi_mot_egr").SetXValue("");
		}	
		else
		{		
			CtrlEnabled("f_egreso", true);
			CtrlEnabled("oi_mot_egr", true);
		}
	}

}
